        gStems.append("line")
          .attr("x1", xH).attr("x2", xH)
          .attr("y1", axisY).attr("y2", yTop)
          .attr("stroke", d.color).attr("stroke-width", 1.5)
          .attr("stroke-opacity", 0.65);

