  // Gamma pdf helper; fills `weights` in place and normalizes
  function updateWeights(meanGI, sdGI) {
    const shape = (meanGI * meanGI) / (sdGI * sdGI);
    const scale = (sdGI * sdGI) / meanGI;
    let total = 0;
    weights[0] = 0;
    for (let s = 1; s &lt;= T; s++) {
      const v = Math.pow(s, shape - 1) * Math.exp(-s / scale);
      weights[s] = v;
      total += v;
    }
    if (total &gt; 0) for (let s = 1; s &lt;= T; s++) weights[s] /= total;
  }

  // Mutable state
