  const rtLine = d3.line().x(d =&gt; barCx[d.t]).y(d =&gt; rtY(d.rt));

  // ────────── Controls (day t is now draggable, so only GI sliders) ──────────
  const controls = document.createElement("div");
  controls.style.cssText = "display:flex;gap:20px;margin:0 0 10px;align-items:flex-end;flex-wrap:wrap;";
