  const formula = document.createElement("div");
  formula.style.cssText = "margin:0 0 6px;padding:14px 18px;background:#f8fafc;border-radius:6px;border:1px solid #e2e8f0;color:#1e293b;";
  const fMain = document.createElement("div");
  fMain.className = "cori-formula";
  formula.appendChild(fStyle); formula.appendChild(fMain);

  const legend = document.createElement("div");
  legend.style.cssText = "font-size:13px;color:#64748b;margin-top:12px;line-height:1.8;";
  legend.innerHTML = `
    &lt;span style="display:inline-block;width:14px;height:12px;background:#e2e8f0;vertical-align:middle;margin-right:2px;"&gt;&lt;/span&gt;
    I&lt;sub&gt;t−s&lt;/sub&gt; past incidence &nbsp;·&nbsp;
    &lt;span style="display:inline-block;width:14px;height:12px;background:#a78bfa;vertical-align:middle;margin-right:2px;"&gt;&lt;/span&gt;
    w&lt;sub&gt;s&lt;/sub&gt; generation interval &nbsp;·&nbsp;
    &lt;span style="display:inline-block;width:14px;height:12px;background:#f59e0b;vertical-align:middle;margin-right:2px;"&gt;&lt;/span&gt;
    I&lt;sub&gt;t−s&lt;/sub&gt;·w&lt;sub&gt;s&lt;/sub&gt; product &nbsp;·&nbsp;
    &lt;span style="display:inline-block;width:14px;height:12px;background:#dc2626;vertical-align:middle;margin-right:2px;"&gt;&lt;/span&gt;
    I&lt;sub&gt;t&lt;/sub&gt; today &nbsp;·&nbsp;
    &lt;span style="display:inline-block;width:22px;height:0;border-top:2.5px solid #0891b2;vertical-align:middle;margin-right:2px;"&gt;&lt;/span&gt;
