      .text(t);
  }
  for (let t = 0; t &lt;= T_MAX; t += 3) {
    gridG.append("line")
      .attr("x1", xScale(t)).attr("x2", xScale(t))
      .attr("y1", 0).attr("y2", innerH)
      .attr("stroke", "#f1f5f9");
    gridG.append("text")
      .attr("x", xScale(t)).attr("y", innerH + 16)
      .attr("text-anchor", "middle")
      .attr("font-family", `"SF Mono",Menlo,Consolas,monospace`)
      .attr("font-size", 10).attr("fill", "#64748b")
      .text(t);
  }
  plotG.append("text")
    .attr("x", innerW / 2).attr("y", innerH + 36)
    .attr("text-anchor", "middle")
    .attr("font-family", "system-ui").attr("font-size", 11).attr("fill", "#475569")
    .text("time t");

  // Layers in plot
  const theoryPath  = plotG.append("path")
    .attr("fill", "none").attr("stroke", "#0f172a")
    .attr("stroke-width", 2).attr("stroke-dasharray", "5,5");
  const empiricalPath = plotG.append("path")
    .attr("fill", "none").attr("stroke", "#dc2626")
    .attr("stroke-width", 2.5);
  const cursor = plotG.append("line")
    .attr("y1", 0).attr("y2", innerH)
    .attr("stroke", "#94a3b8").attr("stroke-width", 1).attr("stroke-dasharray", "3,3");
  const cursorDot = plotG.append("circle")
    .attr("r", 4).attr("fill", "#dc2626").attr("stroke", "#fff").attr("stroke-width", 1.5);

  // Legend (inside plot)
  const lg = plotG.append("g").attr("transform", `translate(${innerW - 200}, 6)`);
  lg.append("line").attr("x1", 0).attr("x2", 22).attr("y1", 6).attr("y2", 6)
    .attr("stroke", "#0f172a").attr("stroke-width", 2).attr("stroke-dasharray", "5,5");
  lg.append("text").attr("x", 28).attr("y", 9)
    .attr("font-family", "system-ui").attr("font-size", 11).attr("fill", "#334155")
    .text("e^(−λt) — analytic S(t)");
  lg.append("line").attr("x1", 0).attr("x2", 22).attr("y1", 24).attr("y2", 24)
    .attr("stroke", "#dc2626").attr("stroke-width", 2.5);
  lg.append("text").attr("x", 28).attr("y", 27)
    .attr("font-family", "system-ui").attr("font-size", 11).attr("fill", "#334155")
    .text("empirical cohort fraction");

  // ── Cohort state ──
  let people = [];     // { idx, cx, cy, tEvent }
  let history = [];    // { t, frac }
  let tNow   = 0;
  let raf    = null;
  let lastFrame = null;
  let running = false;

  function laidOutGrid(N) {
    // Square-ish grid that fits the left panel
    const availW = LEFT_W - PAD * 2;
    const availH = H - 36 - PAD;
    const cols = Math.ceil(Math.sqrt(N * availW / availH));
    const rows = Math.ceil(N / cols);
    const cellW = availW / cols;
    const cellH = availH / rows;
    const r = Math.max(3, Math.min(9, Math.min(cellW, cellH) / 2 - 2));
    const out = [];
    for (let i = 0; i &lt; N; i++) {
      const c = i % cols, rr = Math.floor(i / cols);
      out.push({
        idx: i,
        cx: cellW * (c + 0.5),
        cy: cellH * (rr + 0.5),
        r
      });
    }
    return out;
  }

  function reset() {
    cancelAnimationFrame(raf);
    raf = null;
    running = false;
    runBtn.setText("▶  Run");
    tNow = 0;
    const N = SL_N.val();
    const lam = SL_lambda.val();
    const grid = laidOutGrid(N);
    people = grid.map(g =&gt; ({
      ...g,
      // Exponential waiting time with rate λ; deterministic-ish via Math.random
      tEvent: -Math.log(1 - Math.random()) / lam
    }));
    history = [{ t: 0, frac: 1 }];
    drawDots();
    drawCurves();
  }

  function drawDots() {
    const sel = dotsG.selectAll("circle").data(people, d =&gt; d.idx);
    sel.enter().append("circle")
      .merge(sel)
      .attr("cx", d =&gt; d.cx).attr("cy", d =&gt; d.cy).attr("r", d =&gt; d.r)
      .attr("fill", d =&gt; d.tEvent &lt;= tNow ? "#dc2626" : "#3b82f6")
      .attr("opacity", d =&gt; d.tEvent &lt;= tNow ? 0.95 : 0.85)
      .attr("stroke", "#fff").attr("stroke-width", 0.8);
    sel.exit().remove();
  }

  function drawCurves() {
    const lam = SL_lambda.val();

    // Analytic survival curve
    const N_PTS = 200;
    const theory = [];
    for (let i = 0; i &lt;= N_PTS; i++) {
      const t = T_MAX * i / N_PTS;
      theory.push({ t, s: Math.exp(-lam * t) });
    }
    const lineFn = d3.line().x(d =&gt; xScale(d.t)).y(d =&gt; yScale(d.s));
    theoryPath.datum(theory).attr("d", lineFn);

    // Empirical step curve
    const stepFn = d3.line()
      .curve(d3.curveStepAfter)
      .x(d =&gt; xScale(d.t)).y(d =&gt; yScale(d.frac));
    empiricalPath.datum(history).attr("d", stepFn);

    // Cursor at current t
    const cur = history.length ? history[history.length - 1] : { t: 0, frac: 1 };
    cursor.attr("x1", xScale(cur.t)).attr("x2", xScale(cur.t));
    cursorDot.attr("cx", xScale(cur.t)).attr("cy", yScale(cur.frac));
  }

  function tick(now) {
    if (!running) return;
    if (lastFrame == null) lastFrame = now;
    const dt = Math.min(0.25, (now - lastFrame) / 1000) * 1.0; // 1 sim sec / wall sec
    lastFrame = now;
    tNow = Math.min(T_MAX, tNow + dt);

    // Count survivors
    let surv = 0;
    for (const p of people) if (p.tEvent &gt; tNow) surv++;
    const frac = surv / people.length;
    history.push({ t: tNow, frac });

    drawDots();
    drawCurves();

    if (tNow &gt;= T_MAX) {
      running = false;
      runBtn.setText("▶  Run");
      raf = null;
      return;
    }
    raf = requestAnimationFrame(tick);
  }

  function toggleRun() {
    if (tNow &gt;= T_MAX) reset();
    if (running) {
      running = false;
      runBtn.setText("▶  Resume");
      cancelAnimationFrame(raf);
      raf = null;
    } else {
      running = true;
      lastFrame = null;
      runBtn.setText("⏸  Pause");
      raf = requestAnimationFrame(tick);
    }
  }

  // ── Wire up controls ──
  SL_lambda.input.addEventListener("input", () =&gt; {
    SL_lambda.sync();
    // Re-sample event times so the cohort respects the new hazard
    reset();
  });
  SL_N.input.addEventListener("input", () =&gt; {
    SL_N.sync();
    reset();
  });
  runBtn.el.addEventListener("click", toggleRun);
  resetBtn.el.addEventListener("click", reset);

  wrapper.appendChild(ctrlRow);
  wrapper.appendChild(svg.node());

  const caption = document.createElement("div");
  caption.style.cssText = "font-size:12px;color:#64748b;margin-top:10px;line-height:1.55;";
  caption.innerHTML = `
    Each &lt;span style="color:#3b82f6;font-weight:600;"&gt;blue&lt;/span&gt; dot is a susceptible whose
    waiting time to infection is drawn from &lt;span style="font-style:italic;"&gt;Exp&lt;/span&gt;(λ).
    When the clock fires, the dot turns &lt;span style="color:#dc2626;font-weight:600;"&gt;red&lt;/span&gt;.
    The red step curve is the cohort fraction still susceptible — the survival function S(t).
    The dashed black curve is e&lt;sup&gt;−λt&lt;/sup&gt;, the analytic solution of both the survival ODE
    Ṡ = −λS and the SIR susceptible equation when the force of infection λ is constant.
  `;
  wrapper.appendChild(caption);

  reset();
  return wrapper;
}







Linking survival analysis to infectious disease modelling







Survival analysis
Infectious disease modelling
Explanation




Survival function \(S(t)=P(T&gt;t)\)
Proportion susceptible in a cohort model
At each moment, the curve of remaining susceptibles mirrors a survival curve.


Hazard ratio
Relative risk under intervention
Compare two forces of infection (e.g. with vs without masks) → HR = \(\lambda_1/\lambda_0\).


Competing risks
Multiple exit routes from S (e.g. infection by strain A vs strain B)
Each strain has its own hazard; the sub-hazards sum to the total risk of leaving S.


Cumulative hazard \(H(t)=\int_0^t h(u)\,du\)
Attack rate over time
\(1-\exp[-H(t)]\) gives the cumulative proportion ever infected—often called the final size in a closed SIR outbreak.


Time-varying covariate in Cox model
Seasonal contact pattern \(\beta(t)\)
A sinusoidal \(\beta(t)\) modulates the hazard exactly like a time-varying coefficient in survival analysis.


Generation-time / waiting-time density \(f(t)\)
Serial interval distribution
The PDF of when an infectee infects others drives renewal-equation models just as \(f(t)\) drives failure timing.


Mixture cure model
Partial immunity / vaccination
A fraction \(\pi\) is “cured” (fully immune); the rest face the usual infection hazard.


Left truncation (enter study late)
Seeding an epidemic
Only individuals present at time \(t_0\) are modelled; earlier infections are truncated away.




