SIR_ODE &lt;- function(time, state, parameters) {
  with(as.list(c(state, parameters)), {
    # rate of change
    dS &lt;- -beta * S * I
    dI &lt;- beta * S * I - gamma * I
    dR &lt;- gamma * I
    # return the rate of change
    list(c(dS, dI, dR))
  })# end with(as.list ...
}
